import { Mail, Linkedin, Github, Phone } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

const links = [
  { href:'mailto:karemalwy1@gmail.com',              label:'karemalwy1@gmail.com', Icon: Mail },
  { href:'https://www.linkedin.com/in/karem-basem',  label:'LinkedIn',             Icon: Linkedin },
  { href:'https://github.com/Kareem-Basem',           label:'GitHub',               Icon: Github },
  { href:'tel:+201062294558',                         label:'+20 106 229 4558',     Icon: Phone },
];

export default function Contact() {
  const { dark, lang } = useApp();
  const tr = t[lang];

  // Dark contact uses a deep section
  const bg    = dark ? '#0a0a10' : '#1a1a2e';
  const tHead = dark ? '#f0f0f8' : '#ffffff';
  const tSub  = dark ? 'rgba(255,255,255,0.45)' : 'rgba(255,255,255,0.55)';
  const amberEm = '#f0a500';

  return (
    <>
      <section id="contact"
        style={{ background: bg }}
        className="py-28 px-[5%] relative overflow-hidden transition-colors duration-300">

        {/* Subtle glow */}
        <div className="absolute w-[500px] h-[500px] rounded-full pointer-events-none"
          style={{
            background: 'radial-gradient(circle, rgba(240,165,0,0.07), transparent 70%)',
            top: '50%', left: '50%', transform: 'translate(-50%,-50%)',
          }} />

        {/* Blob */}
        <div className="blob-hero w-[420px] h-[420px] opacity-[.04] top-[-80px] right-[-80px]"
          style={{ background: '#f0a500', position: 'absolute', pointerEvents: 'none' }} />

        <div className="relative z-10 max-w-2xl">
          <p className="text-xs font-semibold tracking-[.14em] uppercase mb-3"
            style={{ color: amberEm, background: 'rgba(240,165,0,0.12)', border: '1px solid rgba(240,165,0,0.25)', display: 'inline-block', padding: '4px 12px', borderRadius: 999 }}>
            {tr.conTag}
          </p>

          <h2 className="font-serif-display tracking-tight leading-[.95] mb-5"
            style={{ fontSize: 'clamp(3rem,7vw,6rem)', color: tHead }}
            dangerouslySetInnerHTML={{ __html: tr.conTitle.replace('<em>', `<em style="font-style:italic;color:${amberEm};font-family:'DM Serif Display',serif;">`).replace('</em>','</em>') }} />

          <p className="text-[.96rem] leading-[1.8] mb-8 max-w-[460px]" style={{ color: tSub }}>
            {tr.conSub}
          </p>

          <div className="flex flex-wrap gap-2.5">
            {links.map(({ href, label, Icon }) => (
              <a key={label}
                href={href}
                target={href.startsWith('http') ? '_blank' : undefined}
                rel="noreferrer"
                className="flex items-center gap-2 px-4 py-2.5 rounded-full text-sm font-medium transition-all hover:-translate-y-0.5"
                style={{
                  background: 'rgba(255,255,255,0.07)',
                  border: '1.5px solid rgba(255,255,255,0.12)',
                  color: 'rgba(255,255,255,0.65)',
                  backdropFilter: 'blur(12px)',
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.borderColor = amberEm;
                  e.currentTarget.style.color = amberEm;
                  e.currentTarget.style.background = 'rgba(240,165,0,0.10)';
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.borderColor = 'rgba(255,255,255,0.12)';
                  e.currentTarget.style.color = 'rgba(255,255,255,0.65)';
                  e.currentTarget.style.background = 'rgba(255,255,255,0.07)';
                }}>
                <Icon size={14} />
                {label}
              </a>
            ))}
          </div>
        </div>
      </section>

      <footer
        style={{ background: dark ? '#06060a' : '#111124' }}
        className="px-[5%] py-5 flex flex-col md:flex-row justify-between items-center gap-2 transition-colors duration-300">
        <span className="text-[.72rem]" style={{ color: 'rgba(255,255,255,0.25)' }}>© 2025 Kareem Basem Fathi</span>
        <span className="text-[.72rem]" style={{ color: 'rgba(255,255,255,0.25)' }}>MIS · Sadat Academy · Asyut, Egypt</span>
      </footer>
    </>
  );
}
